class Solution:
    def minOperations(self, s1: str, s2: str, x: int) -> int:
        n = len(s1)
        diff = [i for i in range(n) if s1[i] != s2[i]]
        m = len(diff)

        if m == 0:
            return 0

        if m % 2 != 0:
            return -1

        # dp[i][j]: min cost to fix first i differences with j flips
        dp = [[float('inf')] * (m + 1) for _ in range(m + 1)]
        dp[0][0] = 0

        for i in range(1, m + 1):
            for j in range(i + 1):
                if j % 2 == 0:
                    # Use the first operation (cost x) to flip two differences
                    if i - j >= 2:
                        dp[i][j] = min(dp[i][j], dp[i - 2][j] + x)
                    # Use the second operation (cost 1) to flip adjacent differences
                    if i - j >= 1:
                        dp[i][j] = min(dp[i][j], dp[i - 1][j] + 1)
                else:
                    # Use the second operation (cost 1) to flip adjacent differences
                    if i - j >= 1:
                        dp[i][j] = min(dp[i][j], dp[i - 1][j] + 1)

        return dp[m][0] if dp[m][0] != float('inf') else -1
